import React, { useEffect, useState } from 'react';
import { getTasksWithResponses, createTask } from '../services/api';
import AILoadingState from '../components/AILoadingState';

interface Task {
  id: number;
  created_by: number;
  prompt: string;
  status: string;
  created_at: string;
}

const TasksPage: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const data = await getTasksWithResponses();
      setTasks(data);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const handleCreateTask = async () => {
    if (!prompt.trim()) {
      setError('Please enter a prompt');
      return;
    }
    setLoading(true);
    setError('');
    try {
      await createTask({ created_by: 1, prompt });
      setPrompt('');
      fetchTasks();
    } catch (err) {
      setError('Failed to create task');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '3rem 2rem', maxWidth: '800px', margin: '0 auto' }}>

      <div style={{ marginBottom: '2rem', animation: 'fadeInUp 0.5s ease both' }}>
        <h1 style={{ color: 'white', fontWeight: 800, fontSize: '2rem', marginBottom: '0.4rem' }}>Tasks</h1>
        <p style={{ color: 'rgba(255,255,255,0.45)', fontSize: '0.95rem' }}>
          Create a prompt and all 3 AI models respond automatically in parallel.
        </p>
      </div>

      {/* Create Task Form */}
      <div style={{
        background: 'rgba(255,255,255,0.05)',
        backdropFilter: 'blur(20px)',
        WebkitBackdropFilter: 'blur(20px)',
        border: '1px solid rgba(255,255,255,0.1)',
        borderRadius: '16px',
        padding: '1.75rem',
        marginBottom: '2rem',
        animation: 'fadeInUp 0.5s ease 0.1s both'
      }}>
        <h2 style={{ color: 'rgba(255,255,255,0.9)', marginBottom: '1rem', fontSize: '1.05rem', fontWeight: 600 }}>
          Create New Task
        </h2>
        <textarea
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="Enter a prompt for AI models to answer..."
          disabled={loading}
          style={{
            width: '100%',
            minHeight: '100px',
            padding: '0.85rem',
            borderRadius: '10px',
            border: '1px solid rgba(255,255,255,0.12)',
            background: 'rgba(255,255,255,0.06)',
            color: 'white',
            fontSize: '0.95rem',
            marginBottom: '1rem',
            boxSizing: 'border-box',
            resize: 'vertical',
            outline: 'none',
            opacity: loading ? 0.6 : 1,
          }}
        />
        {error && (
          <p style={{ color: '#f87171', marginBottom: '0.75rem', fontSize: '0.9rem' }}>{error}</p>
        )}
        <button
          onClick={handleCreateTask}
          disabled={loading}
          style={{
            background: loading
              ? 'rgba(99,102,241,0.4)'
              : 'linear-gradient(135deg, #6366f1, #0ea5e9)',
            color: 'white',
            border: 'none',
            padding: '0.65rem 1.5rem',
            borderRadius: '10px',
            cursor: loading ? 'not-allowed' : 'pointer',
            fontSize: '0.95rem',
            fontWeight: 600,
            boxShadow: loading ? 'none' : '0 4px 15px rgba(99,102,241,0.4)',
            transition: 'all 0.2s ease'
          }}
        >
          {loading ? 'Querying models...' : '⚡ Create Task'}
        </button>

        {loading && (
          <div style={{
            marginTop: '1rem',
            padding: '0.75rem 1rem',
            background: 'rgba(251,191,36,0.1)',
            border: '1px solid rgba(251,191,36,0.3)',
            borderRadius: '10px',
            display: 'flex',
            alignItems: 'center',
            gap: '0.6rem',
            marginBottom: '0.5rem'
        }}>
            <span style={{ fontSize: '1.1rem' }}>⚠️</span>
            <p style={{ color: '#fbbf24', fontSize: '0.875rem', fontWeight: 600, margin: 0 }}>
              Do not navigate away, refresh, or close this tab — AI models are running in the background.
            </p>
          </div>
        )}
        {loading && <AILoadingState />}
      </div>

      {/* Tasks List */}
      <h2 style={{ color: 'rgba(255,255,255,0.9)', marginBottom: '1rem', fontSize: '1.05rem', fontWeight: 600 }}>
        All Tasks
      </h2>
      {tasks.length === 0 ? (
        <p style={{ color: 'rgba(255,255,255,0.35)' }}>No tasks yet. Create one above.</p>
      ) : (
        tasks.map((task, i) => (
          <div key={task.id} style={{
            background: 'rgba(255,255,255,0.04)',
            backdropFilter: 'blur(12px)',
            WebkitBackdropFilter: 'blur(12px)',
            border: '1px solid rgba(255,255,255,0.08)',
            borderRadius: '12px',
            padding: '1.25rem',
            marginBottom: '0.85rem',
            animation: `fadeInUp 0.4s ease ${i * 0.05}s both`
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
              <span style={{ fontWeight: 700, color: 'rgba(255,255,255,0.7)', fontSize: '0.85rem' }}>
                TASK #{task.id}
              </span>
              <span style={{
                background: task.status === 'completed'
                  ? 'rgba(16,185,129,0.15)'
                  : 'rgba(245,158,11,0.15)',
                color: task.status === 'completed' ? '#34d399' : '#fbbf24',
                padding: '0.2rem 0.7rem',
                borderRadius: '999px',
                fontSize: '0.78rem',
                fontWeight: 600,
                border: `1px solid ${task.status === 'completed' ? 'rgba(52,211,153,0.3)' : 'rgba(251,191,36,0.3)'}`
              }}>
                {task.status}
              </span>
            </div>
            <p style={{ color: 'rgba(255,255,255,0.85)', marginBottom: '0.5rem', fontSize: '0.95rem', lineHeight: 1.5 }}>
              {task.prompt}
            </p>
            <p style={{ color: 'rgba(255,255,255,0.25)', fontSize: '0.78rem' }}>
              {new Date(task.created_at).toLocaleString()}
            </p>
          </div>
        ))
      )}
    </div>
  );
};

export default TasksPage;
